namespace BgControls.Windows.Controls;/// <summary>/// 提供与选项卡项（TabItem）操作相关的常用路由 UI 命令的静态类./// </summary>public static class TabItemCommands{    /// <summary>    /// Gets 一个命令，该命令用于从 <see cref="ItemsControl.Items"/> 或 <see cref="ItemsControl.ItemsSource"/> 中移除选项卡项.    /// </summary>    /// <value>    /// 关闭选项卡项的路由命令.    /// </value>    public static RoutedUICommand Close { get; private set; }    /// <summary>    /// Gets 一个命令，该命令用于切换选项卡项的固定（Pin）状态.    /// </summary>    /// <value>    /// 切换固定状态的路由命令.    /// </value>    public static RoutedUICommand TogglePin { get; private set; }    static TabItemCommands()    {        // 初始化关闭命令，描述为从项集合中移除选项卡项        Close = new RoutedUICommand("从项集合或项源中移除该选项卡项.", "Close", typeof(TabItemCommands));        // 初始化切换固定命令，描述为固定或取消固定选项卡项        TogglePin = new RoutedUICommand("固定或取消固定该选项卡项.", "TogglePin", typeof(TabItemCommands));    }}